  "inlineSchema": "// Prisma schema for CartSniper\n// Using SQLite for hackathon simplicity (swap to PostgreSQL for production)\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"sqlite\"\n  url      = env(\"DATABASE_URL\")\n}\n\nmodel User {\n  id        String   @id @default(cuid())\n  email     String   @unique\n  password  String // bcrypt hashed\n  pushToken String? // Expo push notification token\n  latitude  Float? // User's location for nearby stores\n  longitude Float?\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  carts  Cart[]\n  alerts Alert[]\n}\n\nmodel Product {\n  id        String   @id @default(cuid())\n  barcode   String   @unique\n  name      String\n  brand     String?\n  category  String?\n  imageUrl  String?\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  prices    Price[]\n  cartItems CartItem[]\n  alerts    Alert[]\n}\n\nmodel Store {\n  id               String  @id @default(cuid())\n  name             String\n  slug             String  @unique // walmart, loblaws, nofrills, freshco, metro\n  logoUrl          String?\n  latitude         Float\n  longitude        Float\n  address          String?\n  priceMatchPolicy String? // Description of store's price match policy\n\n  prices Price[]\n}\n\nmodel Price {\n  id        String   @id @default(cuid())\n  productId String\n  storeId   String\n  price     Float\n  salePrice Float? // If on sale\n  inStock   Boolean  @default(true)\n  unit      String? // \"per kg\", \"each\", etc.\n  scrapedAt DateTime @default(now())\n\n  product Product @relation(fields: [productId], references: [id])\n  store   Store   @relation(fields: [storeId], references: [id])\n\n  @@unique([productId, storeId])\n  @@index([productId])\n  @@index([storeId])\n}\n\nmodel Cart {\n  id             String   @id @default(cuid())\n  userId         String\n  name           String   @default(\"My Cart\")\n  optimizedTotal Float? // Calculated best total\n  createdAt      DateTime @default(now())\n  updatedAt      DateTime @updatedAt\n\n  user  User       @relation(fields: [userId], references: [id])\n  items CartItem[]\n}\n\nmodel CartItem {\n  id        String @id @default(cuid())\n  cartId    String\n  productId String\n  quantity  Int    @default(1)\n\n  cart    Cart    @relation(fields: [cartId], references: [id], onDelete: Cascade)\n  product Product @relation(fields: [productId], references: [id])\n\n  @@unique([cartId, productId])\n}\n\nmodel Alert {\n  id          String    @id @default(cuid())\n  userId      String\n  productId   String\n  targetPrice Float // Notify when price drops below this\n  triggered   Boolean   @default(false)\n  triggeredAt DateTime?\n  createdAt   DateTime  @default(now())\n\n  user    User    @relation(fields: [userId], references: [id])\n  product Product @relation(fields: [productId], references: [id])\n\n  @@unique([userId, productId])\n}\n",
